const toggler = document.getElementById("toggle");
toggler.addEventListener("click", toggle);

function toggle() {
  document.getElementsByClassName("overlay")[0].style.width = "100%";
}

const close = document.getElementById("closebtn");
close.addEventListener("click", closeNav);

function closeNav() {
  document.getElementsByClassName("overlay")[0].style.width = "0%";
}

const scriptURL =
  "https://script.google.com/macros/s/AKfycbz-BX5ykrr4Rr8d8SkjZjTWwulyk0TLsVbrzouZWrKTuJjRZ7E/exec";
const form = document.forms["submit-to-google-sheet"];

form.addEventListener("submit", (e) => {
  e.preventDefault();
  fetch(scriptURL, { method: "POST", body: new FormData(form) })
    .then((response) => {
      alert("Your message has been sent");
      location.reload(true);
    })
    .catch((error) => console.error("Error!", error.message));
});
